# Generated by openai (gpt-5.4)
# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

from fastapi import FastAPI, HTTPException, Query
from fastapi.responses import FileResponse
from pydantic import BaseModel
from typing import List, Optional, Literal
import os
import mimetypes
from datetime import datetime

app = FastAPI(title="File Explorer API")

UPLOADS_BASE_DIR = os.path.abspath("uploads")


class DirectoryEntry(BaseModel):
    name: str
    path: str
    type: Literal["file", "directory"]
    size: Optional[int] = None


class DirectoryListResponse(BaseModel):
    path: str
    entries: List[DirectoryEntry]


class FileInfoResponse(BaseModel):
    name: str
    path: str
    type: Literal["file", "directory"]
    size: int
    created_at: str
    modified_at: str
    mime_type: Optional[str] = None


def get_user_root(user_id: str) -> str:
    return os.path.abspath(os.path.join(UPLOADS_BASE_DIR, user_id))


def resolve_user_path(user_id: str, relative_path: str = "") -> str:
    user_root = get_user_root(user_id)
    normalized_relative = os.path.normpath(relative_path or "")
    if normalized_relative == ".":
        normalized_relative = ""
    full_path = os.path.abspath(os.path.join(user_root, normalized_relative))
    if os.path.commonpath([user_root, full_path]) != user_root:
        raise HTTPException(status_code=403, detail="Access outside user root is not allowed")
    return full_path


def ensure_user_root_exists(user_id: str) -> str:
    user_root = get_user_root(user_id)
    if not os.path.isdir(user_root):
        raise HTTPException(status_code=404, detail="User root directory not found")
    return user_root


def to_relative_user_path(user_root: str, full_path: str) -> str:
    rel = os.path.relpath(full_path, user_root)
    return "" if rel == "." else rel.replace("\\", "/")


@app.get("/files/list", response_model=DirectoryListResponse)
def list_directory(
    user_id: str = Query(..., description="User identifier"),
    path: str = Query("", description="Path relative to the user's root directory"),
):
    user_root = ensure_user_root_exists(user_id)
    target_path = resolve_user_path(user_id, path)

    if not os.path.exists(target_path):
        raise HTTPException(status_code=404, detail="Path not found")
    if not os.path.isdir(target_path):
        raise HTTPException(status_code=400, detail="Path is not a directory")

    entries = []
    try:
        for entry_name in sorted(os.listdir(target_path)):
            entry_full_path = os.path.join(target_path, entry_name)
            is_dir = os.path.isdir(entry_full_path)
            entries.append(
                DirectoryEntry(
                    name=entry_name,
                    path=to_relative_user_path(user_root, entry_full_path),
                    type="directory" if is_dir else "file",
                    size=None if is_dir else os.path.getsize(entry_full_path),
                )
            )
    except OSError as e:
        raise HTTPException(status_code=500, detail=f"Failed to list directory: {str(e)}")

    return DirectoryListResponse(
        path=to_relative_user_path(user_root, target_path),
        entries=entries,
    )


@app.get("/files/info", response_model=FileInfoResponse)
def get_file_info(
    user_id: str = Query(..., description="User identifier"),
    path: str = Query(..., description="Path relative to the user's root directory"),
):
    user_root = ensure_user_root_exists(user_id)
    target_path = resolve_user_path(user_id, path)

    if not os.path.exists(target_path):
        raise HTTPException(status_code=404, detail="Path not found")

    stat = os.stat(target_path)
    is_dir = os.path.isdir(target_path)
    mime_type, _ = mimetypes.guess_type(target_path)

    return FileInfoResponse(
        name=os.path.basename(target_path) or os.path.basename(user_root),
        path=to_relative_user_path(user_root, target_path),
        type="directory" if is_dir else "file",
        size=stat.st_size,
        created_at=datetime.fromtimestamp(stat.st_ctime).isoformat(),
        modified_at=datetime.fromtimestamp(stat.st_mtime).isoformat(),
        mime_type=None if is_dir else mime_type,
    )


@app.get("/files/download")
def download_file(
    user_id: str = Query(..., description="User identifier"),
    path: str = Query(..., description="Path relative to the user's root directory"),
):
    resolve_user_path(user_id, "")
    target_path = resolve_user_path(user_id, path)

    if not os.path.exists(target_path):
        raise HTTPException(status_code=404, detail="File not found")
    if not os.path.isfile(target_path):
        raise HTTPException(status_code=400, detail="Path is not a file")

    filename = os.path.basename(target_path)
    media_type, _ = mimetypes.guess_type(target_path)

    return FileResponse(
        path=target_path,
        filename=filename,
        media_type=media_type or "application/octet-stream",
    )